class Solution:
    def maximumLength(self, s):
        n = len(s)
        best = -1
        for length in range(1, n + 1):
            counts = {}
            for i in range(n - length + 1):
                sub = s[i:i + length]
                first = sub[0]
                is_special = True
                for ch in sub:
                    if ch != first:
                        is_special = False
                        break
                if is_special:
                    counts[sub] = counts.get(sub, 0) + 1
            for c in counts.values():
                if c >= 3:
                    best = max(best, length)
        return best

