class Solution:
    def maximumLength(self, s: str) -> int:
        runs = {}
        n = len(s)
        i = 0
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            length = j - i
            c = s[i]
            lst = runs.setdefault(c, [])
            lst.append(length)
            lst.sort(reverse=True)
            if len(lst) > 3:
                lst.pop()
            i = j
        ans = -1
        for lst in runs.values():
            r1 = lst[0] if len(lst) > 0 else 0
            r2 = lst[1] if len(lst) > 1 else 0
            r3 = lst[2] if len(lst) > 2 else 0
            if r1 >= 3:
                ans = max(ans, r1 - 2)
            if r1 >= 1 and r2 >= 1:
                cand = min(r1 - 1, r2)
                if cand >= 1:
                    ans = max(ans, cand)
            if r3 >= 1:
                ans = max(ans, r3)
        return ans

